import React, { useState } from 'react';
import LandingPage from './pages/LandingPage';
import MonitoringPage from './pages/MonitoringPage';
import ModelAnalysisPage from './pages/ModelAnalysisPage';

function App() {
  const [currentPage, setCurrentPage] = useState('landing');

  const renderPage = () => {
    switch (currentPage) {
      case 'landing':
        return <LandingPage onNavigate={() => setCurrentPage('monitor')} />;
      case 'monitor':
        return <MonitoringPage onNavigate={() => setCurrentPage('landing')} onNavigateToModels={() => setCurrentPage('models')} />;
      case 'models':
        return <ModelAnalysisPage onNavigateBack={() => setCurrentPage('monitor')} />;
      default:
        return <LandingPage onNavigate={() => setCurrentPage('monitor')} />;
    }
  };

  return (
    <div className="App">
      {renderPage()}
    </div>
  );
}

export default App;
